export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult<T extends Record<string, unknown> = Record<string, unknown>> {
  rows: T[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: T) => boolean): T[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, T[]>;
}

const DEFAULT_DELIMITER = ",";
const DEFAULT_QUOTE = '"';

const numberPattern = /^[-+]?\d+(?:\.\d+)?$/;

const coerceValue = (value: string): unknown => {
  const trimmed = value.trim();

  if (trimmed === "") {
    return null;
  }

  const lower = trimmed.toLowerCase();
  if (lower === "null") {
    return null;
  }

  if (lower === "true") {
    return true;
  }

  if (lower === "false") {
    return false;
  }

  if (numberPattern.test(trimmed)) {
    return Number(trimmed);
  }

  return value;
};

const matchLineSeparator = (
  input: string,
  index: number,
  lineSeparator?: string
): number => {
  if (lineSeparator) {
    return input.startsWith(lineSeparator, index) ? lineSeparator.length : 0;
  }

  const ch = input[index];
  if (ch === "\r") {
    return input[index + 1] === "\n" ? 2 : 1;
  }
  if (ch === "\n") {
    return 1;
  }
  return 0;
};

const parseRows = (
  input: string,
  delimiter: string,
  quote: string,
  lineSeparator?: string
): { rows: string[][]; errors: CSVError[] } => {
  const rows: string[][] = [];
  const errors: CSVError[] = [];

  if (input.length === 0) {
    return { rows, errors };
  }

  let row: string[] = [];
  let field = "";
  let inQuotes = false;

  const delimiterLength = delimiter.length;

  for (let i = 0; i < input.length; i += 1) {
    const ch = input[i];

    if (inQuotes) {
      if (input.startsWith(quote, i)) {
        const nextIndex = i + quote.length;
        if (input.startsWith(quote, nextIndex)) {
          field += quote;
          i += quote.length;
        } else {
          inQuotes = false;
          i += quote.length - 1;
        }
      } else {
        field += ch;
      }
      continue;
    }

    if (input.startsWith(quote, i)) {
      inQuotes = true;
      i += quote.length - 1;
      continue;
    }

    if (delimiterLength > 0 && input.startsWith(delimiter, i)) {
      row.push(field);
      field = "";
      i += delimiterLength - 1;
      continue;
    }

    const lineSepLength = matchLineSeparator(input, i, lineSeparator);
    if (lineSepLength > 0) {
      row.push(field);
      rows.push(row);
      row = [];
      field = "";
      i += lineSepLength - 1;
      continue;
    }

    field += ch;
  }

  if (inQuotes) {
    errors.push({
      row: rows.length + 1,
      message: "Unclosed quoted field.",
    });
  }

  row.push(field);
  rows.push(row);

  const endsWithLineSeparator = lineSeparator
    ? input.endsWith(lineSeparator)
    : input.endsWith("\n") || input.endsWith("\r");
  if (endsWithLineSeparator) {
    const lastRow = rows[rows.length - 1];
    if (lastRow.length === 1 && lastRow[0] === "") {
      rows.pop();
    }
  }

  return { rows, errors };
};

export const parseCSV = (
  input: string,
  options: CSVOptions = {}
): CSVResult => {
  const delimiter = options.delimiter ?? DEFAULT_DELIMITER;
  const quote = options.quote ?? DEFAULT_QUOTE;
  const lineSeparator = options.lineSeparator;

  const { rows: rawRows, errors } = parseRows(
    input,
    delimiter,
    quote,
    lineSeparator
  );

  if (rawRows.length === 0) {
    return {
      rows: [],
      headers: [],
      errors,
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
  }

  const headers = rawRows[0].map((header) => header.trim());
  const dataRows = rawRows.slice(1);
  const parsedRows: Record<string, unknown>[] = [];

  dataRows.forEach((rowValues, index) => {
    if (rowValues.length !== headers.length) {
      errors.push({
        row: index + 2,
        message: `Expected ${headers.length} fields but got ${rowValues.length}.`,
      });
    }

    const row: Record<string, unknown> = {};
    headers.forEach((header, headerIndex) => {
      const value = rowValues[headerIndex] ?? "";
      row[header] = coerceValue(value);
    });
    parsedRows.push(row);
  });

  const sum = (column: string): number => {
    return parsedRows.reduce((total, row) => {
      const value = row[column];
      if (typeof value === "number" && Number.isFinite(value)) {
        return total + value;
      }
      return total;
    }, 0);
  };

  const average = (column: string): number => {
    let total = 0;
    let count = 0;
    parsedRows.forEach((row) => {
      const value = row[column];
      if (typeof value === "number" && Number.isFinite(value)) {
        total += value;
        count += 1;
      }
    });
    return count === 0 ? 0 : total / count;
  };

  const count = (): number => parsedRows.length;

  const groupBy = (column: string): Map<unknown, Record<string, unknown>[]> => {
    const map = new Map<unknown, Record<string, unknown>[]>();
    parsedRows.forEach((row) => {
      const key = row[column];
      const group = map.get(key);
      if (group) {
        group.push(row);
      } else {
        map.set(key, [row]);
      }
    });
    return map;
  };

  return {
    rows: parsedRows,
    headers,
    errors,
    filter: (predicate) => parsedRows.filter(predicate),
    sum,
    average,
    count,
    groupBy,
  };
};

import { parseCSV } from "./csv-parser";

const assert = (condition: boolean, message: string): void => {
  if (!condition) {
    throw new Error(message);
  }
};

const assertEqual = (actual: unknown, expected: unknown, message: string) => {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `${message}. Expected ${JSON.stringify(expected)} but got ${JSON.stringify(
        actual
      )}`
    );
  }
};

const assertMap = (
  actual: Map<unknown, unknown>,
  expected: Map<unknown, unknown>,
  message: string
) => {
  assert(actual.size === expected.size, `${message}: map size mismatch`);
  expected.forEach((value, key) => {
    assert(actual.has(key), `${message}: missing key ${String(key)}`);
    assertEqual(actual.get(key), value, `${message}: value mismatch for ${key}`);
  });
};

const testBasicParsing = () => {
  const input = "name,age\nAlice,30\nBob,25";
  const result = parseCSV(input);
  assertEqual(result.headers, ["name", "age"], "Headers should match");
  assert(result.rows.length === 2, "Should parse two rows");
  assertEqual(result.rows[0], { name: "Alice", age: 30 }, "Row 1 mismatch");
  assertEqual(result.rows[1], { name: "Bob", age: 25 }, "Row 2 mismatch");
};

const testQuotedFields = () => {
  const input =
    "name,notes\n\"Alice\",\"Likes apples, oranges\"\n\"Bob\",\"No commas\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].notes, "Likes apples, oranges", "Quoted comma");
  assertEqual(result.rows[1].notes, "No commas", "Quoted string");
};

const testEscapedQuotes = () => {
  const input = "name,quote\nAlice,\"She said \"\"Hello\"\"\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].quote, 'She said "Hello"', "Escaped quotes");
};

const testCustomDelimiters = () => {
  const input = "name;age|Alice;30|Bob;20";
  const result = parseCSV(input, { delimiter: ";", lineSeparator: "|" });
  assertEqual(result.rows[0], { name: "Alice", age: 30 }, "Custom delimiter row");
  assertEqual(result.rows[1], { name: "Bob", age: 20 }, "Custom delimiter row 2");
};

const testTypeCoercion = () => {
  const input = "n,f,b1,b2,nu,empty,str\n42,3.14,true,FALSE,null,,hello";
  const result = parseCSV(input);
  assertEqual(result.rows[0], {
    n: 42,
    f: 3.14,
    b1: true,
    b2: false,
    nu: null,
    empty: null,
    str: "hello",
  }, "Type coercion failed");
};

const testMalformedRows = () => {
  const input = "a,b\n1\n2,3,4";
  const result = parseCSV(input);
  assert(result.errors.length === 2, "Should report two errors");
  assertEqual(result.errors[0].row, 2, "First error row number");
  assertEqual(result.errors[1].row, 3, "Second error row number");
  assertEqual(result.rows[0], { a: 1, b: null }, "Missing field coerced to null");
  assertEqual(result.rows[1], { a: 2, b: 3 }, "Extra field ignored");
};

const testFilter = () => {
  const input = "name,age\nAlice,30\nBob,25\nCara,40";
  const result = parseCSV(input);
  const filtered = result.filter((row) => (row.age as number) > 30);
  assertEqual(filtered, [{ name: "Cara", age: 40 }], "Filter result mismatch");
};

const testAggregation = () => {
  const input = "group,value\nA,10\nB,5\nA,15\nB,20";
  const result = parseCSV(input);
  assertEqual(result.sum("value"), 50, "Sum incorrect");
  assertEqual(result.average("value"), 12.5, "Average incorrect");
  assertEqual(result.count(), 4, "Count incorrect");

  const expected = new Map<unknown, unknown>([
    ["A", [
      { group: "A", value: 10 },
      { group: "A", value: 15 },
    ]],
    ["B", [
      { group: "B", value: 5 },
      { group: "B", value: 20 },
    ]],
  ]);
  const grouped = result.groupBy("group");
  assertMap(grouped, expected, "GroupBy mismatch");
};

const testEdgeCases = () => {
  const empty = parseCSV("");
  assertEqual(empty.headers, [], "Empty input headers");
  assertEqual(empty.rows, [], "Empty input rows");

  const singleColumn = parseCSV("value\n1\n2");
  assertEqual(singleColumn.rows, [{ value: 1 }, { value: 2 }], "Single column");

  const singleRow = parseCSV("a,b\n1,2");
  assertEqual(singleRow.rows, [{ a: 1, b: 2 }], "Single row");

  const largeField = "x".repeat(10000);
  const largeInput = `col\n\"${largeField}\"`;
  const largeResult = parseCSV(largeInput);
  assertEqual(largeResult.rows[0], { col: largeField }, "Large field mismatch");
};

const runTests = () => {
  testBasicParsing();
  testQuotedFields();
  testEscapedQuotes();
  testCustomDelimiters();
  testTypeCoercion();
  testMalformedRows();
  testFilter();
  testAggregation();
  testEdgeCases();
  console.log("All CSV parser tests passed.");
};

runTests();

